function:
{
  "record_vehicle_details": {
  "type": "function",
  "function": {
  "name": "record_vehicle_details",
  "description": "Record the detailed status and basic information of the customer's vehicle.",
  "parameters": {
  "type": "object",
  "properties": {
  "brand_model": {
  "type": "string",
  "description": "The brand and model of the vehicle provided by the customer."
  },
  "license_plate": {
  "type": "string",
  "description": "The license plate number of the vehicle."
  },
  "registration_date": {
  "type": "string",
  "description": "The registration date of the vehicle provided by the customer."
  },
  "expiry_date": {
  "type": "string",
  "description": "The specific expiration date of the vehicle's annual inspection. [requirement] Format yyyy-mm-dd."
  },
  "current_mileage": {
  "type": "number",
  "description": "The current total mileage of the vehicle in kilometers."
  },
  "past_inspection_failures": {
  "type": "string",
  "description": "Any history of past inspection failures."
  },
  "modification_status": {
  "type": "string",
  "description": "The status indicating if the vehicle has unauthorized modifications. [requirement] Input \"Yes\" or \"No\"."
  },
  "recent_mechanical_faults": {
  "type": "string",
  "description": "Any recent mechanical faults reported by the customer."
  }
  },
  "required": [
  "brand_model",
  "license_plate",
  "registration_date",
  "expiry_date",
  "current_mileage",
  "past_inspection_failures",
  "modification_status",
  "recent_mechanical_faults"
  ]
  }
  }
  },
  "register_appointment": {
  "type": "function",
  "function": {
  "name": "register_appointment",
  "description": "Register the customer's personal information and the confirmed appointment time.",
  "parameters": {
  "type": "object",
  "properties": {
  "customer_name": {
  "type": "string",
  "description": "The full name provided by the customer."
  },
  "contact_number": {
  "type": "string",
  "description": "The contact phone number confirmed by the customer."
  },
  "appointment_time": {
  "type": "string",
  "description": "The scheduled date and time for the inspection. [requirement] Format yyyy-mm-dd hh:mm."
  }
  },
  "required": [
  "customer_name",
  "contact_number",
  "appointment_time"
  ]
  }
  }
  },
  "send_confirmation_voucher": {
  "type": "function",
  "function": {
  "name": "send_confirmation_voucher",
  "description": "Send the digital appointment voucher and location details to the customer.",
  "parameters": {
  "type": "object",
  "properties": {
  "contact_number": {
  "type": "string",
  "description": "The phone number to which the confirmation message will be sent."
  }
  },
  "required": [
  "contact_number"
  ]
  }
  }
  }
 }
